import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';

export default function StudentDashboard() {
  const { user }              = useAuth();
  const [data, setData]       = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/student/stats')
      .then(res => { setData(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  const { stats } = data || { stats: {} };

  const patternRows = [
    { component: 'Best of Q1 / Q2',     max: 10, note: 'Higher of Q1 or Q2',         bg: '#eff6ff' },
    { component: 'Best of Q3 / Q4',     max: 10, note: 'Higher of Q3 or Q4',         bg: '#f0fdf4' },
    { component: 'Best of Q5 / Q6',     max: 10, note: 'Higher of Q5 or Q6',         bg: '#fef3c7' },
    { component: 'Question Total ÷ 2',  max: 15, note: 'Sum of above ÷ 2',           bg: '#f8fafc', italic: true },
    { component: 'SHA',                 max: 10, note: 'Surprise / Home Assignment',  bg: '#fff' },
    { component: 'Assignment',          max: 5,  note: 'Assignment marks',            bg: '#f8fafc' },
    { component: 'Mid Total',           max: 30, note: 'Per mid exam',                bg: '#e0f2fe', bold: true },
    { component: 'Final Marks',         max: 30, note: '80% higher mid + 20% lower', bg: '#d1fae5', bold: true },
  ];

  return (
    <div>
      {/* Welcome banner */}
      <div className="info-box" style={{ marginBottom: 20 }}>
        👋 Welcome, <strong>{user?.name}</strong> &nbsp;|&nbsp;
        Roll: <strong>{user?.rollNumber}</strong> &nbsp;|&nbsp;
        Dept: <strong>{user?.department?.name}</strong> &nbsp;|&nbsp;
        Sem: <strong>{user?.semester}</strong>
      </div>

      {/* Stats */}
      <div className="stats-grid">
        <div className="stat-card blue">  <div className="stat-icon">📅</div><div><div className="stat-value">{stats.currentSemester || '—'}</div><div className="stat-label">Current Semester</div></div></div>
        <div className="stat-card cyan">  <div className="stat-icon">📚</div><div><div className="stat-value">{stats.totalSubjects  || 0}</div> <div className="stat-label">Total Subjects</div></div></div>
        <div className="stat-card yellow"><div className="stat-icon">📝</div><div><div className="stat-value">{stats.mid1Count      || 0}</div> <div className="stat-label">Mid-1 Results</div></div></div>
        <div className="stat-card green"> <div className="stat-icon">📋</div><div><div className="stat-value">{stats.mid2Count      || 0}</div> <div className="stat-label">Mid-2 Results</div></div></div>
        <div className="stat-card purple"><div className="stat-icon">⭐</div><div><div className="stat-value">{stats.avgMid1        || 0}</div> <div className="stat-label">Avg Mid-1</div></div></div>
        <div className="stat-card red">   <div className="stat-icon">🏆</div><div><div className="stat-value">{stats.finalReadyCount|| 0}</div> <div className="stat-label">Finals Ready</div></div></div>
      </div>

      {/* Marks Pattern — card with stacked rows, no table */}
      <div className="card">
        <div className="card-header"><span className="card-title">📐 Marks Pattern</span></div>
        <div className="card-body" style={{ padding: 0 }}>
          {patternRows.map((row, i) => (
            <div key={i} style={{
              display: 'flex', alignItems: 'center',
              padding: '12px 16px',
              background: row.bg,
              borderBottom: i < patternRows.length - 1 ? '1px solid #f1f5f9' : 'none',
              gap: 12,
            }}>
              {/* Component name */}
              <div style={{ flex: 2, fontSize: 13, fontWeight: row.bold ? 700 : 400, fontStyle: row.italic ? 'italic' : 'normal', color: 'var(--text)' }}>
                {row.component}
              </div>

              {/* Max marks badge */}
              <div style={{ flexShrink: 0, textAlign: 'center' }}>
                <span style={{
                  display: 'inline-block',
                  padding: '2px 10px', borderRadius: 20,
                  fontSize: 13, fontWeight: 700,
                  background: row.bold ? '#1a56db' : '#e2e8f0',
                  color: row.bold ? 'white' : 'var(--text)',
                  minWidth: 36, textAlign: 'center'
                }}>
                  {row.max}
                </span>
              </div>

              {/* Note */}
              <div style={{ flex: 3, fontSize: 12, color: row.bold ? 'var(--text)' : 'var(--text-muted)', textAlign: 'right' }}>
                {row.note}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
